// ── Real membership tier hook
function useTierLevel(): TierLevel {
  const { tier } = useMembership();
  const { isAdmin } = useAdminRole();
  const rank = isAdmin ? 3 : getTierRank(tier);
  return (rank >= 3 ? 3 : rank >= 2 ? 2 : rank >= 1 ? 1 : 0) as TierLevel;
}

// ── Web Audio Engine
function useAudioEngine() {
  const ctxRef = useRef<AudioContext | null>(null);
  const gainRef = useRef<GainNode | null>(null);
  const activeRef = useRef<AudioNode[]>([]);
  const [playing, setPlaying] = useState<string | null>(null);
  const [volume, setVolume] = useState(0.4);

  const init = useCallback(() => {
    if (!ctxRef.current) {
      ctxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      gainRef.current = ctxRef.current.createGain();
      gainRef.current.gain.value = volume;
      gainRef.current.connect(ctxRef.current.destination);
    }
  }, [volume]);

  const stopAll = useCallback(() => {
    activeRef.current.forEach(n => { try { (n as OscillatorNode).stop(); } catch {} n.disconnect(); });
    activeRef.current = [];
    setPlaying(null);
  }, []);

  const playPreset = useCallback((preset: AudioPreset) => {
    init();
    stopAll();
    const ctx = ctxRef.current!;
    const gain = gainRef.current!;
    if (preset.type === "om") {
      [[136.1,0.55],[272.2,0.28],[408.3,0.12],[544.4,0.05]].forEach(([f,g]) => {
        const osc = ctx.createOscillator(); const gn = ctx.createGain();
        osc.frequency.value = f; osc.type = "sine"; gn.gain.value = g;
        osc.connect(gn); gn.connect(gain); osc.start();
        activeRef.current.push(osc, gn);
      });
    } else if (preset.type === "tone") {
      const osc = ctx.createOscillator();
      osc.frequency.value = preset.freq; osc.type = "sine";
      osc.connect(gain); osc.start(); activeRef.current.push(osc);
    } else {
      const merger = ctx.createChannelMerger(2); merger.connect(gain);
      const oscL = ctx.createOscillator(); const oscR = ctx.createOscillator();
      oscL.frequency.value = preset.freq; oscL.type = "sine";
      oscR.frequency.value = preset.freq + (preset.beat ?? 0); oscR.type = "sine";
      oscL.connect(merger, 0, 0); oscR.connect(merger, 0, 1);
      oscL.start(); oscR.start(); activeRef.current.push(oscL, oscR, merger);
    }
    setPlaying(preset.id);
  }, [init, stopAll]);

  const updateVolume = useCallback((v: number) => {
    setVolume(v);
    if (gainRef.current) gainRef.current.gain.value = v;
  }, []);

  useEffect(() => () => { stopAll(); ctxRef.current?.close(); }, []);
  return { playing, playPreset, stopAll, volume, updateVolume };
}

// ── Sacred Geometry Canvas
const SacredGeometry: React.FC<{ active: boolean }> = ({ active }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const rafRef = useRef<number>(0);
  useEffect(() => {
    const canvas = canvasRef.current; if (!canvas) return;
    const ctx = canvas.getContext("2d")!;
    let angle = 0;
    const draw = () => {
      const s = canvas.width; ctx.clearRect(0,0,s,s);
      ctx.save(); ctx.translate(s/2, s/2);
      [[0.40,1,3,0.70],[0.33,-1,3,0.55],[0.26,1,3,0.40],[0.19,-1,3,0.30],[0.12,1,6,0.20]].forEach(([r,dir,pts,alpha],i) => {
        ctx.save(); ctx.rotate(angle*(dir as number)+(i*Math.PI/(pts as number)));
        ctx.strokeStyle = `rgba(212,175,55,${alpha})`; ctx.lineWidth = 0.8; ctx.beginPath();
        for(let p=0;p<(pts as number);p++){const a=(p*2*Math.PI)/(pts as number);p===0?ctx.moveTo(Math.cos(a)*(r*s),Math.sin(a)*(r*s)):ctx.lineTo(Math.cos(a)*(r*s),Math.sin(a)*(r*s));}
        ctx.closePath(); ctx.stroke(); ctx.restore();
      });
      ctx.beginPath(); ctx.arc(0,0,2.5,0,Math.PI*2); ctx.fillStyle="#D4AF37"; ctx.fill();
      ctx.beginPath(); ctx.arc(0,0,s*0.43,0,Math.PI*2); ctx.strokeStyle="rgba(212,175,55,0.12)"; ctx.lineWidth=1; ctx.stroke();
      ctx.restore(); angle += active ? 0.004 : 0.001;
      rafRef.current = requestAnimationFrame(draw);
    };
    draw();
    return () => cancelAnimationFrame(rafRef.current);
  }, [active]);
  return <canvas ref={canvasRef} width={160} height={160} style={{display:"block",margin:"0 auto"}} />;
};

// ── Breathing Guide
const BREATH_PHASES = [{label:"INHALE",dur:4000,sz:110},{label:"HOLD",dur:4000,sz:110},{label:"EXHALE",dur:4000,sz:64},{label:"HOLD",dur:4000,sz:64}];
const BreathingGuide: React.FC<{active:boolean}> = ({active}) => {
  const [pi,setPi] = useState(0); const [sz,setSz] = useState(64); const [ct,setCt] = useState(0);
  useEffect(()=>{
    if(!active){setPi(0);setSz(64);return;}
    const ph=BREATH_PHASES[pi]; const tgt=ph.sz; const start=sz; const t0=performance.now(); let raf:number;
    const anim=(now:number)=>{const t=Math.min((now-t0)/ph.dur,1);setSz(start+(tgt-start)*t);if(t<1){raf=requestAnimationFrame(anim);}};
    raf=requestAnimationFrame(anim);
    const timer=setTimeout(()=>{setPi(i=>(i+1)%4);if(pi===3)setCt(c=>c+1);},ph.dur);
    return()=>{cancelAnimationFrame(raf);clearTimeout(timer);};
  },[active,pi]);
  return(
    <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:10,padding:"16px 0"}}>
      <button onClick={() => navigate('/siddha-portal')} style={{ position:'fixed', top:16, left:16, zIndex:9999, background:'rgba(5,5,5,0.88)', backdropFilter:'blur(12px)', border:'none', cursor:'pointer', fontFamily:"'Plus Jakarta Sans',sans-serif", fontSize:10, fontWeight:800, letterSpacing:'0.35em', textTransform:'uppercase', color:'rgba(212,175,55,0.5)', padding:'8px 14px', borderRadius:8 }}>← SIDDHA PORTAL</button>
      <div style={{width:sz,height:sz,borderRadius:"50%",background:"rgba(212,175,55,0.08)",border:"2px solid rgba(212,175,55,0.4)",transition:"width 0.1s,height 0.1s",boxShadow:active?`0 0 ${Math.round(sz/3)}px rgba(212,175,55,0.2)`:"none",display:"flex",alignItems:"center",justifyContent:"center"}}>
        {active && <Wind size={16} color="#D4AF37" />}
      </div>
      <div style={{color:"#D4AF37",fontSize:12,fontWeight:800,letterSpacing:"0.2em",minHeight:16}}>{active?BREATH_PHASES[pi].label:"PRESS BEGIN"}</div>
      {active && <div style={{color:"rgba(255,255,255,0.3)",fontSize:9,letterSpacing:"0.4em"}}>CYCLE {ct+1} · 4-4-4-4 KRIYA BREATH</div>}
    </div>
  );
};

