const AudioPanel: React.FC<{audio:ReturnType<typeof useAudioEngine>}> = ({audio}) => {
  const [showBreath,setShowBreath] = useState(false);
  const [breathActive,setBreathActive] = useState(false);
  return(
    <div style={{position:"fixed",bottom:0,left:0,right:0,zIndex:900,background:"rgba(5,5,5,0.96)",borderTop:"1px solid rgba(212,175,55,0.2)",backdropFilter:"blur(30px)",padding:"10px 14px"}}>
      <div style={{maxWidth:980,margin:"0 auto"}}>
        {showBreath && <BreathingGuide active={breathActive}/>}
        <div style={{display:"flex",alignItems:"center",gap:7,flexWrap:"wrap" as const}}>
          <div style={{color:"rgba(212,175,55,0.6)",fontSize:9,fontWeight:800,letterSpacing:"0.35em",flexShrink:0}}>
            {audio.playing ? `🔊 ${AUDIO_PRESETS.find(p=>p.id===audio.playing)?.label??""}` : "SACRED AUDIO"}
          </div>
          {AUDIO_PRESETS.map(p=>(
            <button key={p.id} onClick={()=>audio.playing===p.id?audio.stopAll():audio.playPreset(p)}
              style={{background:audio.playing===p.id?"rgba(212,175,55,0.2)":"rgba(212,175,55,0.06)",border:`1px solid ${audio.playing===p.id?"rgba(212,175,55,0.5)":"rgba(212,175,55,0.15)"}`,borderRadius:9,padding:"5px 10px",color:"#D4AF37",fontSize:9,fontWeight:800,letterSpacing:"0.22em",cursor:"pointer",fontFamily:"inherit",whiteSpace:"nowrap" as const}}>
              {p.emoji} {p.label}
            </button>
          ))}
          {audio.playing && <button onClick={audio.stopAll} style={{background:"rgba(255,80,80,0.08)",border:"1px solid rgba(255,80,80,0.2)",borderRadius:9,padding:"5px 10px",color:"rgba(255,150,150,0.8)",fontSize:9,fontWeight:800,letterSpacing:"0.22em",cursor:"pointer",fontFamily:"inherit"}}>■ STOP</button>}
          <button onClick={()=>{setShowBreath(s=>!s);if(showBreath)setBreathActive(false);}}
            style={{background:"rgba(255,255,255,0.04)",border:"1px solid rgba(255,255,255,0.1)",borderRadius:9,padding:"5px 10px",color:"rgba(255,255,255,0.5)",fontSize:9,fontWeight:800,letterSpacing:"0.22em",cursor:"pointer",fontFamily:"inherit",display:"flex",alignItems:"center",gap:4}}>
            <Wind size={10}/>BREATH
          </button>
          {showBreath && <button onClick={()=>setBreathActive(a=>!a)} style={{background:"rgba(212,175,55,0.1)",border:"1px solid rgba(212,175,55,0.3)",borderRadius:9,padding:"5px 10px",color:"#D4AF37",fontSize:9,fontWeight:800,letterSpacing:"0.22em",cursor:"pointer",fontFamily:"inherit"}}>
            {breathActive?"⏸ PAUSE":"▶ BEGIN"}
          </button>}
          <div style={{display:"flex",alignItems:"center",gap:5,marginLeft:"auto"}}>
            <Volume2 size={10} color="rgba(212,175,55,0.5)"/>
            <input type="range" min={0} max={1} step={0.05} value={audio.volume}
              onChange={e=>audio.updateVolume(parseFloat(e.target.value))}
              style={{width:65,accentColor:"#D4AF37"}}/>
          </div>
        </div>
      </div>
    </div>
  );
};

